import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Quote: empty and single-item base premiums ===
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("plain sword → 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("plain amulet → 75 G (60 base + 10 first insurance + 5 fee)");
  it.todo("plain staff → 95 G (80 base + 10 first insurance + 5 fee)");
  it.todo("plain potion → 55 G (40 base + 10 first insurance + 5 fee)");
  it.todo("1 rune → 40 G (25 base + 10 first insurance + 5 fee)");
  it.todo("1 moonstone → 40 G (25 base + 10 first insurance + 5 fee)");

  // === Quote: component blocks ===
  it.todo("2 runes → 65 G (50 base + 10 first insurance + 5 fee)");
  it.todo("3 runes → 75 G (60 base block + 10 first insurance + 5 fee)");
  it.todo("4 runes → 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("7 runes → 190 G (175 base + 10 first insurance + 5 fee)");
  it.todo("2 runes + 1 moonstone → 90 G (75 base + 10 first insurance + 5 fee)");
  it.todo("3 runes + 3 moonstones → 135 G (120 base + 10 first insurance + 5 fee)");

  // === Quote: item-specific modifiers ===
  it.todo("cursed sword → 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");
  it.todo("sword enchantment 5 (high enchantment) → 145 G (100 base + 30 high enchantment + 10 first insurance + 5 fee)");
  it.todo("sword enchantment 4, not cursed → 115 G (no high-enchantment surcharge)");
  it.todo("sword enchantment 4, cursed → 165 G (only curse surcharge)");
  it.todo("cursed sword enchantment 5 → 195 G (100 base + 50 curse + 30 high enchantment + 10 first insurance + 5 fee)");

  // === Quote: policy-wide modifiers ===
  it.todo("loyalty discount applies at exactly 2 years → 95 G (100 base + 10 first insurance − 20 loyalty + 5 fee)");
  it.todo("first insurance surcharge always applies regardless of customer history → plain sword at 3 years is 115 G");
  it.todo("follow-up contract discount (second quote step) → 100 G (100 base + 10 first insurance − 15 follow-up + 5 fee)");

  // === Quote: modifier scope and integration ===
  it.todo("cursed sword + plain amulet → cursed surcharge applies only to the cursed item, not the policy total");
  it.todo("newcomer with cursed sword (0 years, first contract) → 165 G");
  it.todo("long-standing customer's second contract (3 years, 2nd quote) with cursed sword enchantment 7 → 160 G");

  // === Quote: multiple items and rounding ===
  it.todo("two swords → insurance sum 2000 G, base premium 200 G");
  it.todo("premium rounding in MHPCO's favor: 197.5 → 198 G");
  it.todo("unknown item type → non-zero exit code and error to stderr, no stdout results");

  // === Claim: standard reimbursement ===
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (full minus 100 deductible)");

  // === Claim: special clauses ===
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon material: full reimbursement minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% rule then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both clauses: 50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule then deductible)");

  // === Claim: deductible per damage event ===
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per damaged item)");

  // === Claim: cap and cap exhaustion ===
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword policy → cap 2000 G (unmodified insurance value)");
  it.todo("sword + 3 runes policy → insurance sum 1750 G, cap 3500 G");
  it.todo("cap exhaustion: two claims of 1500 G on sword (cap 2000 G) → first 1400 G, second 600 G remaining cap 0 G");

  // === Claim: multiple items and errors ===
  it.todo("two swords insured, two sword damage entries → each treated as separate damage with own deductible");
  it.todo("more damage entries of a type than policy covers → non-zero exit code and error to stderr");
  it.todo("damage to item not in policy → non-zero exit code and error to stderr");
  it.todo("unknown item type in damage → non-zero exit code and error to stderr");
  it.todo("negative damage amount → non-zero exit code and error to stderr");
  it.todo("payout rounding in MHPCO's favor: 350.5 → 350 G");
});

export function processScenario(input: unknown): unknown {
  return { results: [] };
}

