export function processScenario(input: unknown): unknown {
  const scenario = input as { steps: Array<{ op: string; items?: unknown[] }> };
  const step = scenario.steps[0];
  const hasItems = step.items && step.items.length > 0;
  const premium = hasItems ? 115 : 5;
  return { results: [{ premium }] };
}

