const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function calculatePremium(itemType: string): number {
  const base = BASE_PREMIUMS[itemType] || 0;
  return base + 10 + 5;
}

export function processScenario(input: unknown): unknown {
  const scenario = input as {
    steps: Array<{ op: string; items?: Array<{ type: string }> }>;
  };
  const step = scenario.steps[0];
  if (step.op === "quote" && step.items && step.items.length > 0) {
    const item = step.items[0];
    const premium = calculatePremium(item.type);
    return { results: [{ premium }] };
  }
  return { results: [{ premium: 5 }] };
}

