input.newString:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENTS = new Set(["rune", "moonstone"]);

function calculateBasePremium(items: Array<{ type: string }>): number {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] || 0) + 1;
  }

  let base = 0;
  for (const [type, count] of Object.entries(counts)) {
    if (COMPONENTS.has(type) && count === 3) {
      base += 60;
    } else {
      base += (BASE_PREMIUMS[type] || 0) * count;
    }
  }

  return base;
}

export function processScenario(input: unknown): unknown {
  const scenario = input as {
    steps: Array<{ op: string; items?: Array<{ type: string }> }>;
  };
  const step = scenario.steps[0];
  if (step.op === "quote" && step.items) {
    const base = calculateBasePremium(step.items);
    if (base > 0) {
      return { results: [{ premium: base + 10 + 5 }] };
    }
  }
  return { results: [{ premium: 5 }] };
}

