input.content:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

function calculateBasePremium(items: Item[]): number {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] || 0) + 1;
  }

  let base = 0;
  for (const [type, count] of Object.entries(counts)) {
    if (COMPONENT_TYPES.has(type) && count === 3) {
      base += 60;
    } else {
      base += (BASE_PREMIUMS[type] || 0) * count;
    }
  }

  return base;
}

function calculateItemSurcharges(items: Item[]): number {
  let surcharge = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) continue;
    const itemBase = BASE_PREMIUMS[item.type] || 0;
    if (item.cursed) {
      surcharge += itemBase * 0.5;
    }
    if ((item.enchantment ?? 0) >= 5) {
      surcharge += itemBase * 0.3;
    }
  }
  return surcharge;
}

function calculatePolicyModifiers(
  premium: number,
  _years: number,
): number {
  // first insurance surcharge: +10%
  return premium * 1.1;
}

export function processScenario(input: unknown): unknown {
  const scenario = input as {
    customer: { yearsWithMHPCO: number };
    steps: Array<{ op: string; items?: Item[] }>;
  };
  const step = scenario.steps[0];
  if (step.op === "quote" && step.items) {
    const base = calculateBasePremium(step.items);
    const surcharges = calculateItemSurcharges(step.items);
    let premium = base + surcharges;
    premium = calculatePolicyModifiers(
      premium,
      scenario.customer.yearsWithMHPCO,
    );
    premium += 5;
    return { results: [{ premium: Math.ceil(premium) }] };
  }
  return { results: [{ premium: 5 }] };
}

