  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const BASE_PREMIUM_RATES: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

input.oldString:
function calculateItemSurcharges(items: Item[]): number {
  let surcharge = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) continue;
    const itemBase = BASE_PREMIUM_RATES[item.type] || 0;
    if (item.cursed) {
      surcharge += itemBase * 0.5;
    }
    if ((item.enchantment ?? 0) >= 5) {
      surcharge += itemBase * 0.3;
    }
  }
  return surcharge;
}

